import numpy as np

def center_loss(embeddings: np.ndarray, labels: np.ndarray) -> float:
    embeddings = np.asarray(embeddings, dtype=float)
    labels = np.asarray(labels)
    classes = np.unique(labels)
    centers = {}
    for c in classes:
        mask = labels == c
        centers[c] = embeddings[mask].mean(axis=0)
    total = 0.0
    for i, (z, y) in enumerate(zip(embeddings, labels)):
        diff = z - centers[y]
        total += 0.5 * np.dot(diff, diff)
    return float(total / len(embeddings))
